mapper.select:
SELECT t.task_id, t.list_id, t.stage_id, t.title, t.description, t.priority, t.position, t.assignee_id, t.creator_id, t.due_date, t.created_at, t.updated_at, tl.name AS list_name, s.name AS stage_name, assignee.username AS assignee_name, assignee.avatar AS assignee_avatar, creator.username AS creator_name, creator.avatar AS creator_avatar FROM tasks t INNER JOIN task_lists tl ON t.list_id = tl.list_id LEFT JOIN stages s ON t.stage_id = s.stage_id LEFT JOIN users assignee ON t.assignee_id = assignee.user_id LEFT JOIN users creator ON t.creator_id = creator.user_id
AND tl.list_id = #{listId}
AND t.priority = #{priority}
AND t.stage_id = #{stageId}
AND t.assignee_id = #{assigneeId}
AND t.title LIKE CONCAT('%', #{keyword}, '%')
ORDER BY FIELD(t.priority, 'high', 'medium', 'low') ASC, t.position ASC
ORDER BY t.due_date ASC, t.position ASC
ORDER BY t.created_at DESC, t.position ASC
ORDER BY t.position ASC

SELECT t.task_id, t.list_id, t.stage_id, t.title, t.description, t.priority, t.position, t.assignee_id, t.creator_id, t.due_date, t.created_at, t.updated_at, tl.name AS list_name, tl.project_id, p.name AS project_name, p.team_id, tm.name AS team_name, s.name AS stage_name FROM tasks t INNER JOIN task_lists tl ON t.list_id = tl.list_id INNER JOIN projects p ON tl.project_id = p.project_id INNER JOIN teams tm ON p.team_id = tm.team_id LEFT JOIN stages s ON t.stage_id = s.stage_id
AND (t.assignee_id = #{userId} OR t.creator_id = #{userId})
AND t.priority = #{priority}
AND t.list_id = #{listId}
AND p.team_id = #{teamId}
ORDER BY CASE t.priority WHEN 'high' THEN 0 WHEN 'medium' THEN 1 WHEN 'low' THEN 2 ELSE 3 END, t.due_date ASC, t.created_at DESC

SELECT COALESCE(MAX(position), -1)
FROM tasks
WHERE list_id = #{listId}

mapper.update:
UPDATE tasks
SET position = #{position},
    list_id = #{listId}
WHERE task_id = #{taskId}

mapper.select:
SELECT tm.name AS team_name, COUNT(t.task_id) AS total_tasks, SUM(CASE WHEN tl.name = '已完成' THEN 1 ELSE 0 END) AS completed_tasks, SUM(CASE WHEN tl.name = '进行中' THEN 1 ELSE 0 END) AS in_progress_tasks, SUM(CASE WHEN tl.name = '待办' THEN 1 ELSE 0 END) AS todo_tasks, SUM(CASE WHEN t.priority = 'high' THEN 1 ELSE 0 END) AS high_total, SUM(CASE WHEN t.priority = 'high' AND tl.name = '已完成' THEN 1 ELSE 0 END) AS high_completed, SUM(CASE WHEN t.priority = 'medium' THEN 1 ELSE 0 END) AS medium_total, SUM(CASE WHEN t.priority = 'medium' AND tl.name = '已完成' THEN 1 ELSE 0 END) AS medium_completed, SUM(CASE WHEN t.priority = 'low' THEN 1 ELSE 0 END) AS low_total, SUM(CASE WHEN t.priority = 'low' AND tl.name = '已完成' THEN 1 ELSE 0 END) AS low_completed FROM tasks t INNER JOIN task_lists tl ON t.list_id = tl.list_id INNER JOIN projects p ON tl.project_id = p.project_id INNER JOIN teams tm ON p.team_id = tm.team_id
AND tm.team_id = #{teamId}
AND p.project_id = #{projectId}

SELECT u.user_id, u.username, u.avatar, COUNT(t.task_id) AS assigned_tasks, SUM(CASE WHEN tl.name = '已完成' THEN 1 ELSE 0 END) AS completed_tasks, SUM(CASE WHEN t.due_date IS NOT NULL AND t.due_date < NOW() AND tl.name != '已完成' THEN 1 ELSE 0 END) AS overdue_tasks FROM tasks t INNER JOIN task_lists tl ON t.list_id = tl.list_id INNER JOIN projects p ON tl.project_id = p.project_id INNER JOIN team_members tm ON p.team_id = tm.team_id AND t.assignee_id = tm.user_id INNER JOIN users u ON t.assignee_id = u.user_id
AND tm.team_id = #{teamId}
AND p.project_id = #{projectId}
GROUP BY u.user_id, u.username, u.avatar ORDER BY assigned_tasks DESC
